external_knowledge:
- 'standard foot soldiers or horsemen' refers to 'Infantry' and 'Cavalry';
- 'last year' refers to the year 2020;
- 'diverse battle strategy' refers to having more than two unique tactics;
- 'how strong they hit' refers to the average attack strength.

sql:
SELECT COUNT(unit_id) 
FROM scenario_units
WHERE role = 'Front Line';

SELECT user_name
FROM users
WHERE user_id NOT IN (
  SELECT user_id
  FROM unit_profiles
);

SELECT name
FROM units
ORDER BY name DESC;

SELECT u.name, ATAN(us.attack) AS AttackTangent
FROM units u
LEFT JOIN unit_statistics us ON u.unit_id = us.unit_id;

SELECT unit_type_id, name, description
FROM units
WHERE unit_id = 1;
